                        road mask
    @param smooth_dist: Tolerance parameter used to smooth the graph using
                        RDP algorithm
    @return: return ndarray of road keypoints
    """
    if is_gaussian:
        mask /= 255.0
        mask[mask < thresh] = 0
        mask[mask >= thresh] = 1
    h, w = mask.shape
    if is_skeleton:
        ske = mask
    else:
        ske = skeletonize(mask).astype(np.uint16)

